#include<bits/stdc++.h>
using namespace std;
map<string,int>m;
int main()
{
	int t;
	cin>>t;
	int tot=1;
	for(int i=1;i<=t;i++){
		string s,IP;
		cin>>s>>IP;
		int cnt=0,flag=0;
		for(int i=0;i<IP.size();i++){
			if(IP[i]=='0'){
				if(IP[i+1]>='0'&&IP[i+1]<='9'&&IP[i-1]<'0'&&IP[i-1]>'9'){
					cnt=0;
					cout<<"ERR"<<endl;
					flag=1;
					break;
				}
			}
//			cout<<s[i];
			if(IP[i]!='.'&&IP[i]!=':'){
				cnt=cnt*10+IP[i]-'0';
			}else{
//				cout<<cnt<<endl;
				if(IP[i]=='.'&&cnt>255){
					cout<<"ERR"<<endl;
					flag=1;
					break;
				}
				if(cnt>65535){
					cout<<"ERR"<<endl;
					flag=1;
					break;
				}
				cnt=0;
			}
		}
		if(flag)continue;
		int x=0,y=0;
		for(int i=0;i<IP.size();i++){
			if(IP[i]=='.')x++;
			if(IP[i]==':') y++;
			if(x<3&&y>=1){
				cout<<"ERR"<<endl;
				flag=1;
				break;
			}
		}
		if(flag)continue;
		if(x!=3||y!=1){
			cout<<"ERR"<<endl;
			continue;
		}
		if(cnt>65535){
//			cout<<cnt<<endl;
			cout<<"ERR"<<endl;
			continue;
		}
		if(s[0]=='S'){
			if(m.count(IP)){
				cout<<IP<<" "<<endl;
				cout<<"FAIL"<<endl;
			}
			else{
				m[IP]=i;
				cout<<"OK"<<endl;
			}

		}else{
			if(m.count(IP)){
				cout<<m[IP]<<endl;
			}else{
				cout<<"FAIL"<<endl;
			}
		}
	}
}
